/* ===================================================
   SEO PAGES — Rajasthali Tours
   Extends style.css with page-specific overrides
=================================================== */

:root {
  --brand-pink: #e91e8c;
  --brand-gold: #c9a84c;
  --dark-bg: #0a0a0f;
  --dark-card: #12121a;
  --dark-border: rgba(255,255,255,0.08);
  --text-primary: #f5f5f5;
  --text-muted: #999;
  --radius: 12px;
}

/* ---- Base ---- */
.seo-body {
  background: var(--dark-bg);
  color: var(--text-primary);
  font-family: 'Inter', sans-serif;
  margin: 0;
  padding: 0;
}
.seo-body * { box-sizing: border-box; }
.seo-body a { text-decoration: none; }

/* ---- Navigation ---- */
.seo-nav-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  background: rgba(10,10,15,0.95);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--dark-border);
}
.seo-nav-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
  height: 68px;
  display: flex;
  align-items: center;
  gap: 32px;
}
.seo-nav-brand {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}
.seo-nav-brand img {
  width: 40px;
  height: 40px;
  object-fit: contain;
}
.seo-nav-brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.2;
}
.seo-company-name {
  font-family: 'Playfair Display', serif;
  font-size: 1rem;
  font-weight: 700;
  color: #fff;
}
.seo-company-tagline {
  font-size: 0.68rem;
  color: var(--text-muted);
}
.seo-nav-links {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-left: auto;
}
.seo-nav-links a {
  color: #ccc;
  font-size: 0.875rem;
  padding: 6px 12px;
  border-radius: 6px;
  transition: color 0.2s, background 0.2s;
}
.seo-nav-links a:hover { color: #fff; background: rgba(255,255,255,0.07); }
.seo-nav-cta {
  background: var(--brand-pink) !important;
  color: #fff !important;
  font-weight: 600;
  border-radius: 8px !important;
  padding: 7px 16px !important;
}
.seo-nav-cta:hover { background: #c91478 !important; }
.seo-nav-toggle {
  display: none;
  background: none;
  border: none;
  color: #fff;
  font-size: 1.4rem;
  cursor: pointer;
  margin-left: auto;
}
.seo-mobile-nav {
  display: none;
  flex-direction: column;
  background: #13131f;
  border-top: 1px solid var(--dark-border);
  padding: 8px 0;
}
.seo-mobile-nav a {
  padding: 12px 24px;
  color: #ccc;
  font-size: 0.95rem;
  display: block;
  border-bottom: 1px solid var(--dark-border);
}
.seo-mobile-nav a:last-child { border: none; }
.seo-mobile-nav.open { display: flex; }
@media (max-width: 768px) {
  .seo-nav-links { display: none; }
  .seo-nav-toggle { display: block; }
}

/* ---- Hero ---- */
.seo-hero {
  padding: 72px 24px 60px;
}
.seo-hero-inner {
  max-width: 860px;
  margin: 0 auto;
  text-align: center;
}
.seo-breadcrumb {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  font-size: 0.82rem;
  color: var(--text-muted);
  margin-bottom: 24px;
}
.seo-breadcrumb a { color: var(--brand-pink); }
.seo-breadcrumb a:hover { text-decoration: underline; }
.seo-hero-badge {
  display: inline-block;
  background: rgba(233,30,140,0.15);
  border: 1px solid rgba(233,30,140,0.35);
  color: var(--brand-pink);
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 5px 14px;
  border-radius: 20px;
  margin-bottom: 20px;
}
.seo-hero h1 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(1.8rem, 4vw, 3rem);
  font-weight: 700;
  color: #fff;
  line-height: 1.25;
  margin: 0 0 16px;
}
.seo-hero-sub {
  font-size: 1.05rem;
  color: #bbb;
  max-width: 640px;
  margin: 0 auto 32px;
  line-height: 1.7;
}
.seo-hero-sub strong { color: #fff; }
.seo-hero-stats {
  display: flex;
  justify-content: center;
  gap: 32px;
  flex-wrap: wrap;
  margin-top: 16px;
}
.seo-hero-stats > div {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}
.seo-hero-stats strong {
  font-family: 'Playfair Display', serif;
  font-size: 1.5rem;
  color: var(--brand-pink);
}
.seo-hero-stats span {
  font-size: 0.75rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}
.seo-hero-ctas {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
  margin-top: 32px;
}

/* ---- Buttons ---- */
.btn-seo-primary {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--brand-pink);
  color: #fff;
  font-weight: 600;
  font-size: 0.95rem;
  padding: 12px 24px;
  border-radius: 8px;
  transition: background 0.2s, transform 0.15s;
}
.btn-seo-primary:hover { background: #c91478; transform: translateY(-1px); }
.btn-seo-outline {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border: 1.5px solid rgba(255,255,255,0.25);
  color: #fff;
  font-weight: 500;
  font-size: 0.95rem;
  padding: 12px 24px;
  border-radius: 8px;
  transition: border-color 0.2s, background 0.2s;
}
.btn-seo-outline:hover { border-color: var(--brand-pink); background: rgba(233,30,140,0.08); }

/* ---- Main content ---- */
.seo-main { padding: 60px 24px 80px; }
.seo-container { max-width: 1100px; margin: 0 auto; }

/* ---- Section titles ---- */
.seo-main h2 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(1.4rem, 2.5vw, 1.9rem);
  color: #fff;
  margin: 0 0 20px;
}
.seo-main section { margin-bottom: 64px; }

/* ---- Hub intro ---- */
