/* ============================================================
   RAJASTHALI TOURS — main.js
   Handles: preloader, navbar, mobile menu, scroll reveal,
            counters, testimonial slider, back-to-top,
            typing effect, form UX
   ============================================================ */

(function () {
  'use strict';

  /* ---- Preloader ---- */
  function initPreloader() {
    const preloader = document.getElementById('preloader');
    if (!preloader) return;
    const hide = () => {
      preloader.classList.add('loaded');
      document.body.style.overflow = '';
    };
    document.body.style.overflow = 'hidden';
    if (document.readyState === 'complete') {
      setTimeout(hide, 400);
    } else {
      window.addEventListener('load', () => setTimeout(hide, 400));
      setTimeout(hide, 3000);
    }
  }

  /* ---- Navbar: scroll solid + mobile drawer ---- */
  function initNavbar() {
    const navbar   = document.getElementById('navbar');
    const toggle   = document.getElementById('navToggle');
    const navLinks = document.getElementById('navLinks');
    const overlay  = document.getElementById('mobileOverlay');
    if (!navbar) return;

    /* Scroll: transparent → solid */
    const onScroll = () => {
      if (window.scrollY > 60) {
        navbar.classList.add('scrolled');
      } else {
        navbar.classList.remove('scrolled');
      }
      /* Back-to-top */
      const btt = document.querySelector('.back-to-top');
      if (btt) btt.classList.toggle('visible', window.scrollY > 400);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();

    /* Mobile drawer open/close */
    const openMenu = () => {
      toggle && toggle.classList.add('active');
      navLinks && navLinks.classList.add('active');
      overlay && overlay.classList.add('active');
      document.body.style.overflow = 'hidden';
    };
    const closeMenu = () => {
      toggle && toggle.classList.remove('active');
      navLinks && navLinks.classList.remove('active');
      overlay && overlay.classList.remove('active');
      document.body.style.overflow = '';
    };

    toggle  && toggle.addEventListener('click', () =>
      navLinks && navLinks.classList.contains('active') ? closeMenu() : openMenu()
    );
    overlay && overlay.addEventListener('click', closeMenu);

    /* Close drawer when a nav link is tapped */
    navLinks && navLinks.querySelectorAll('a').forEach(a => {
      a.addEventListener('click', closeMenu);
    });

    /* Active link on scroll */
    const sections = document.querySelectorAll('section[id]');
    const links    = navLinks ? navLinks.querySelectorAll('.nav-link') : [];
    const onScrollActive = () => {
      let current = '';
      sections.forEach(s => {
        if (window.scrollY >= s.offsetTop - 100) current = s.id;
      });
      links.forEach(l => {
        l.classList.remove('active');
        if (l.getAttribute('href') === '#' + current) l.classList.add('active');
      });
    };
    window.addEventListener('scroll', onScrollActive, { passive: true });
  }

  /* ---- Scroll Reveal (IntersectionObserver) ---- */
  function initReveal() {
    const els = document.querySelectorAll('.reveal');
    if (!els.length) return;
    if (!('IntersectionObserver' in window)) {
      els.forEach(el => el.classList.add('revealed'));
      return;
    }
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('revealed');
          obs.unobserve(e.target);
        }
      });
    }, { threshold: 0.12 });
    els.forEach(el => obs.observe(el));
  }

  /* ---- Counter animation ---- */
  function animateCounter(el, target, duration) {
    const start = performance.now();
    const update = (now) => {
      const elapsed = now - start;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      el.textContent = Math.round(eased * target).toLocaleString();
      if (progress < 1) requestAnimationFrame(update);
    };
    requestAnimationFrame(update);
  }

  function initCounters() {
    const counterEls = document.querySelectorAll('.count[data-target]');
    if (!counterEls.length) return;
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          const target = parseInt(e.target.dataset.target, 10);
          animateCounter(e.target, target, 1800);
          obs.unobserve(e.target);
        }
      });
    }, { threshold: 0.5 });
    counterEls.forEach(el => obs.observe(el));
  }

  /* ---- Testimonial slider ---- */
  function initTestimonials() {
    const track  = document.querySelector('.testimonial-track');
    const dots   = document.querySelectorAll('.testimonial-dot');
    if (!track || !dots.length) return;

    const cards     = track.querySelectorAll('.testimonial-card');
    let current     = 0;
    let autoTimer   = null;

    const getPerPage = () => window.innerWidth < 768 ? 1 : window.innerWidth < 1024 ? 2 : 3;

    const goTo = (idx) => {
      const perPage = getPerPage();
      const maxIdx  = Math.max(0, cards.length - perPage);
      current = Math.max(0, Math.min(idx, maxIdx));

      /* Card width = container width / perPage */
      const containerW = track.parentElement.offsetWidth;
      const cardW      = (containerW / perPage);
      track.style.transform = `translateX(-${current * cardW}px)`;
      track.style.transition = 'transform 0.6s cubic-bezier(0.25,0.46,0.45,0.94)';

      dots.forEach((d, i) => d.classList.toggle('active', i === current));
    };

    dots.forEach((d, i) => d.addEventListener('click', () => {
      clearInterval(autoTimer);
      goTo(i);
      autoTimer = setInterval(() => goTo((current + 1) % cards.length), 5000);
    }));

    autoTimer = setInterval(() => {
      const perPage = getPerPage();
      const maxIdx  = Math.max(0, cards.length - perPage);
      goTo(current >= maxIdx ? 0 : current + 1);
    }, 5000);

    /* Touch/swipe */
    let startX = 0;
    track.addEventListener('touchstart', e => { startX = e.touches[0].clientX; }, { passive: true });
    track.addEventListener('touchend', e => {
      const diff = startX - e.changedTouches[0].clientX;
      if (Math.abs(diff) > 50) {
        clearInterval(autoTimer);
        goTo(diff > 0 ? current + 1 : current - 1);
        autoTimer = setInterval(() => goTo((current + 1) % cards.length), 5000);
      }
    });

    window.addEventListener('resize', () => goTo(current));
  }

  /* ---- Typing effect ---- */
  function initTyping() {
    const el = document.querySelector('.typed-text');
    if (!el) return;
    const words = ['Rajasthan', 'Jaipur', 'Udaipur', 'Jodhpur', 'Jaisalmer'];
    let wi = 0, ci = 0, deleting = false;
    const type = () => {
      const word = words[wi];
      if (deleting) {
        el.textContent = word.substring(0, ci - 1);
        ci--;
      } else {
        el.textContent = word.substring(0, ci + 1);
        ci++;
      }
      let delay = deleting ? 60 : 120;
      if (!deleting && ci === word.length) { delay = 2200; deleting = true; }
      else if (deleting && ci === 0) { deleting = false; wi = (wi + 1) % words.length; delay = 300; }
      setTimeout(type, delay);
    };
    setTimeout(type, 1000);
  }

  /* ---- Back to top ---- */
  function initBackToTop() {
    const btt = document.querySelector('.back-to-top');
    if (!btt) return;
    btt.addEventListener('click', (e) => {
      e.preventDefault();
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  }

  /* ---- Contact form feedback ---- */
  function initContactForm() {
    const form = document.querySelector('.contact-form');
    if (!form) return;
    form.addEventListener('submit', (e) => {
      const btn = form.querySelector('button[type="submit"]');
      if (!btn) return;
      btn.textContent = 'Sending…';
      btn.disabled = true;
      setTimeout(() => {
        btn.textContent = 'Send Message';
        btn.disabled = false;
      }, 3000);
    });
  }

  /* ---- Gallery lightbox (simple) ---- */
  function initGallery() {
    document.querySelectorAll('.gallery-item').forEach(item => {
      item.addEventListener('click', () => {
        const img = item.querySelector('img');
        if (!img) return;
        const overlay = document.createElement('div');
        overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:99999;display:flex;align-items:center;justify-content:center;cursor:pointer;padding:20px;';
        const image = document.createElement('img');
        image.src = img.src;
        image.alt = img.alt;
        image.style.cssText = 'max-width:90vw;max-height:90vh;object-fit:contain;border-radius:8px;';
        overlay.appendChild(image);
        overlay.addEventListener('click', () => document.body.removeChild(overlay));
        document.body.appendChild(overlay);
      });
    });
  }

  /* ---- Sticky WhatsApp pulse ---- */
  function initWhatsApp() {
    const wa = document.querySelector('.whatsapp-float');
    if (!wa) return;
    setInterval(() => wa.classList.toggle('pulse'), 2000);
  }

  /* ---- Init all ---- */
  document.addEventListener('DOMContentLoaded', () => {
    initPreloader();
    initNavbar();
    initReveal();
    initCounters();
    initTestimonials();
    initTyping();
    initBackToTop();
    initContactForm();
    initGallery();
    initWhatsApp();
  });

})();

