/* ============================================
   RESPONSIVE DESIGN
   ============================================ */
@media (max-width: 1024px) {
  .services-grid { grid-template-columns: repeat(2, 1fr); }
  .service-card.wide { grid-column: span 2; }
  .fleet-grid { grid-template-columns: repeat(2, 1fr); }
  .why-bento { grid-template-columns: repeat(2, 1fr); }
  .cert-grid { grid-template-columns: repeat(3, 1fr); }
  .gallery-grid { grid-template-columns: repeat(2, 1fr); grid-template-rows: auto; }
  .gallery-item:nth-child(1) { grid-column: span 2; }
  .footer-grid { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 768px) {
  .container { padding: 0 var(--space-md); }
  .section-padding { padding: 2rem 0; }

  .top-bar { display: none; }

  .nav-toggle { display: flex; }

  .nav-links {
    position: fixed;
    top: 0;
    right: -100%;
    width: 80%;
    max-width: 360px;
    height: 100vh;
    background: var(--white);
    flex-direction: column;
    padding: 80px 32px 32px;
    gap: 4px;
    box-shadow: -10px 0 40px rgba(0, 0, 0, 0.1);
    transition: right var(--duration-normal) var(--ease-out);
    z-index: 1000;
    align-items: stretch;
  }

  .nav-links.active {
    right: 0;
  }

  .nav-link {
    padding: 14px 16px;
    border-radius: var(--radius-md);
    font-size: 1rem;
    color: var(--gray-800) !important;
  }

  .nav-link:hover,
  .nav-link.active {
    color: var(--brand-pink) !important;
    background: rgba(233, 30, 140, 0.06) !important;
  }

  .nav-cta {
    text-align: center;
    justify-content: center;
    margin-top: var(--space-md);
  }

  .mobile-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    z-index: 999;
    opacity: 0;
    visibility: hidden;
    transition: all var(--duration-normal);
  }

  .mobile-overlay.active {
    opacity: 1;
    visibility: visible;
  }

  .hero-content { padding: var(--space-3xl) 0; }
  .hero-title { font-size: 2.2rem; }
  .hero-stats {
    display: grid !important;
    grid-template-columns: repeat(2, 1fr) !important;
    gap: var(--space-md) !important;
    margin-top: var(--space-xl) !important;
    padding-top: var(--space-md) !important;
  }
  .hero-stat {
    padding: 0 !important;
  }
  .hero-stat:not(:last-child)::after {
    display: none !important;
  }
  .hero-stat .number { font-size: 1.8rem; }

  .about-bento { grid-template-columns: 1fr; gap: var(--space-2xl); }
  .about-bento-image img { height: 320px; }
  .about-experience-badge {
