/* ============================================
   BACK TO TOP
   ============================================ */
.back-to-top {
  position: fixed;
  bottom: 90px;
  right: 20px;
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: var(--gradient-brand);
  color: var(--white);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--shadow-brand);
  z-index: 998;
  opacity: 0;
  visibility: hidden;
  transform: translateY(12px);
  transition: all var(--duration-normal) var(--ease-out);
  cursor: pointer;
}
.back-to-top.visible {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}
.back-to-top svg { width: 18px; height: 18px; }
.back-to-top:hover { transform: translateY(-4px); box-shadow: 0 12px 30px rgba(233,30,140,0.45); }

/* WhatsApp float pulse */
.whatsapp-float.pulse {
  box-shadow: 0 0 0 8px rgba(37, 211, 102, 0);
}

/* ============================================
   RESPONSIVE DESIGN
   ============================================ */

/* ---- 1280px and below: tighten container ---- */
@media (max-width: 1280px) {
  .container { max-width: 1120px; }
}

/* ---- Tablet/medium (max 1024px) ---- */
@media (max-width: 1024px) {
  .services-grid { grid-template-columns: repeat(2, 1fr); }
  .service-card.wide { grid-column: span 2; }
  .fleet-grid { grid-template-columns: repeat(2, 1fr); }
  .why-bento { grid-template-columns: repeat(2, 1fr); }
  .cert-grid { grid-template-columns: repeat(3, 1fr); }
  .gallery-grid { grid-template-columns: repeat(2, 1fr); grid-template-rows: auto; }
  .gallery-item:nth-child(1) { grid-column: span 2; }
  .footer-grid { grid-template-columns: repeat(2, 1fr); }
  .contact-grid { grid-template-columns: 1fr 1fr; gap: var(--space-xl); }
  .about-bento { grid-template-columns: 1fr 1fr; gap: var(--space-2xl); }
}

/* ---- Mobile (max 768px) ---- */
@media (max-width: 768px) {
  /* Base */
  html { font-size: 15px; }
  .container { padding: 0 1rem; }
  .section-padding { padding: 2.5rem 0; }

  /* Top bar — hidden on mobile */
  .top-bar { display: none; }

  /* Navbar — sits at top when top-bar is gone */
  .navbar { top: 0; }
  .navbar .container { height: 64px; }

  /* Hamburger toggle */
  .nav-toggle {
    display: flex;
    padding: 8px;
    margin: -8px;
    min-width: 44px;
    min-height: 44px;
    align-items: center;
    justify-content: center;
  }

  /* Mobile drawer */
  .nav-links {
    position: fixed;
    top: 0;
    right: -100%;
    width: 82%;
    max-width: 320px;
    height: 100vh;
    height: 100dvh;
    background: var(--white);
    flex-direction: column;
    padding: 80px 24px 40px;
    gap: 4px;
    box-shadow: -8px 0 48px rgba(0,0,0,0.18);
    transition: right 0.35s cubic-bezier(0.25,0.46,0.45,0.94);
    z-index: 1001;
    align-items: stretch;
    overflow-y: auto;
  }
  .nav-links.active { right: 0; }

  .nav-link {
    padding: 14px 16px;
    border-radius: var(--radius-md);
    font-size: 1rem;
    font-weight: 500;
    color: var(--gray-800) !important;
    min-height: 44px;
    display: flex;
    align-items: center;
  }
  .nav-link:hover,
  .nav-link.active {
    color: var(--brand-pink) !important;
    background: rgba(233, 30, 140, 0.06) !important;
  }
  .nav-cta {
    background: var(--gradient-brand) !important;
    color: var(--white) !important;
    justify-content: center;
    margin-top: 8px;
    border-radius: var(--radius-full) !important;
    box-shadow: var(--shadow-brand);
  }

  /* Mobile overlay backdrop */
  .mobile-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.55);
    z-index: 1000;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.35s, visibility 0.35s;
  }
  .mobile-overlay.active {
    opacity: 1;
    visibility: visible;
  }

  /* Hero */
  .hero-content { padding: 100px 0 48px; }
  .hero-title { font-size: clamp(1.9rem, 7vw, 2.6rem); }
  .hero-description { font-size: 1rem; }
  .hero-badge { font-size: 0.68rem; padding: 8px 16px; }
  .hero-stats {
    display: grid !important;
    grid-template-columns: repeat(2, 1fr) !important;
    gap: 1rem !important;
    margin-top: 1.5rem !important;
    padding-top: 1rem !important;
  }
  .hero-stat {
    padding: 0.75rem !important;
    background: rgba(255,255,255,0.05);
    border-radius: var(--radius-md);
  }
  .hero-stat:not(:last-child)::after { display: none !important; }
  .hero-stat .number { font-size: 1.6rem; }
  .hero-stat .label { font-size: 0.7rem; }
  .hero-actions { gap: 10px; }
  .hero-scroll-indicator { display: none; }

  /* About */
  .about-bento { grid-template-columns: 1fr; gap: 2rem; }
  .about-bento-image img { height: 280px; }
  .about-experience-badge {
    bottom: 12px !important;
    right: 12px !important;
    width: 100px !important;
    height: 100px !important;
    border-width: 2px !important;
  }
  .about-experience-badge .years { font-size: 1.6rem !important; }
  .about-experience-badge .text { font-size: 0.52rem !important; }
  .about-mini-stats { grid-template-columns: repeat(2, 1fr); gap: 0.5rem; }
  .about-cta-row { flex-direction: column; align-items: stretch; gap: 0.75rem; }
  .about-phone-link { justify-content: center; }

  /* Services */
  .services-grid { grid-template-columns: 1fr; }
  .service-card.wide {
    grid-column: span 1 !important;
    flex-direction: column !important;
    align-items: flex-start !important;
    gap: 1rem !important;
  }
  .service-card.wide .service-icon { margin-bottom: 0.5rem !important; }
  .service-card.wide .service-arrow { margin-top: 0.75rem !important; align-self: flex-start !important; }

  /* Fleet */
  .fleet-grid { grid-template-columns: 1fr; }
  .fleet-card-image { height: 200px; }

  /* Why/Bento */
  .why-bento { grid-template-columns: 1fr; }
  .why-bento-card { flex-direction: column; align-items: flex-start; gap: 0.75rem; }

  /* Certifications */
  .cert-grid { grid-template-columns: repeat(2, 1fr); }
  .cert-card { padding: 1rem; }
  .cert-card img { height: 56px; }

  /* Gallery */
  .gallery-grid { grid-template-columns: 1fr; grid-template-rows: auto; }
  .gallery-item { height: 220px; }
  .gallery-item:nth-child(1) { grid-column: span 1; height: 260px; }

  /* Stats/Counter */
  .counter-grid { grid-template-columns: repeat(2, 1fr); gap: 1rem; }
  .counter-item .count { font-size: 2rem; }

  /* Testimonials */
  .testimonial-card {
    min-width: calc(100vw - 48px);
    width: calc(100vw - 48px);
  }

  /* Contact */
  .contact-grid { grid-template-columns: 1fr; gap: 1.5rem; }
  .form-row { grid-template-columns: 1fr !important; }
  .contact-form { padding: 1.5rem; }

  /* CTA section */
  .cta-section::before { width: 100%; height: 100%; }
  .cta-actions { flex-direction: column; align-items: center; }
  .cta-actions .btn { width: 100%; max-width: 320px; justify-content: center; }

  /* Map */
  .map-section iframe { height: 300px; }

  /* Footer */
  .footer-grid { grid-template-columns: 1fr; gap: 2rem; }
  .footer-bottom { flex-direction: column; gap: 0.75rem; text-align: center; }
  .footer-bottom-links { flex-wrap: wrap; justify-content: center; }

  /* Floating buttons */
  .whatsapp-float { bottom: 16px; right: 16px; width: 52px; height: 52px; }
  .back-to-top { bottom: 80px; right: 16px; width: 40px; height: 40px; }
}

/* ---- Small mobile (max 480px) ---- */
@media (max-width: 480px) {
  html { font-size: 14px; }
  .container { padding: 0 0.875rem; }
  .section-padding { padding: 2rem 0; }

  /* Hero */
  .hero-title { font-size: clamp(1.7rem, 8vw, 2.2rem); }
  .hero-actions { flex-direction: column; }
  .hero-actions .btn { width: 100%; justify-content: center; }
  .hero-badge { letter-spacing: 0.04em; }

  /* Certifications */
  .cert-grid { grid-template-columns: repeat(2, 1fr); gap: 0.75rem; }
  .cert-card { padding: 0.75rem 0.5rem; }

  /* About */
  .about-mini-stats { grid-template-columns: 1fr 1fr; }

  /* Form */
  .form-row { grid-template-columns: 1fr; }

  /* Contact */
  .contact-card { padding: 0.875rem; }

  /* Footer */
  .footer-social { flex-wrap: wrap; }

  /* Gallery */
  .gallery-item { height: 180px; }
  .gallery-item:nth-child(1) { height: 220px; }
}

